code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, CodeBlock, createHighlighter } from 'decantr/components';

code.example:
function CodeComparison({ left, right, caption }) {
  const { div, h3, p } = tags;

  const panel = (label, code, lang) =>
    Card({ class: css('_flex _col _gap0 _overflow[hidden]') },
      Card.Header({},
        h3({ class: css('_textsm _fgmuted _uppercase _tracking[0.05em]') }, label)
      ),
      Card.Body({ class: css('_p0') },
        CodeBlock({ language: lang, highlight: createHighlighter }, code)
      )
    );

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('_grid _gc1 _lg:gc2 _gap6') },
      panel(left.label, left.code, left.lang || 'javascript'),
      panel(right.label, right.code, right.lang || 'javascript')
    ),
    caption ? p({ class: css('_tc _fgmuted _textsm _italic') }, caption) : null
  );
}

// See docs/src/sections/vision-comparison.js for full implementation
// Key elements:
// - Inline syntax highlighting with span({ style: `color:${color}` }, text)
// - One Dark color palette (#c678dd keywords, #e5c07b types, #98c379 strings, etc.)
// - Decantr brand colors for JSON (#0AF3EB cyan keys, #FE4474 pink nested keys)
// - Tech chips: TechChip('React'), TechChip('TypeScript'), etc.
// - Success message with checkmark at bottom-right
// - Highlighted keywords in caption (structure, composition, intent)

